import React, { useEffect, useState } from 'react';
import axios from '../api/axios';
import { useNavigate } from 'react-router-dom';

export default function UserDashboard() {
    const navigate = useNavigate();
    const [stats, setStats] = useState({ activeBookings: 0, totalLots: 0, recentBookings: [] });
    const [lots, setLots] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                // Fetch user's bookings
                const bookingsRes = await axios.get('/bookings/my');
                const active = bookingsRes.data.filter(b => b.status === 'Active' || b.status === 'Booked');

                // Fetch parking lots
                const lotsRes = await axios.get('/parking');

                setStats({
                    activeBookings: active.length,
                    totalLots: lotsRes.data.length,
                    recentBookings: bookingsRes.data.slice(0, 3) // Latest 3
                });

                setLots(lotsRes.data.slice(0, 3)); // Show 3 nearby lots
                setLoading(false);
            } catch (err) {
                console.error("Error loading dashboard data:", err);
                setLoading(false);
            }
        };

        fetchDashboardData();
    }, []);

    if (loading) {
        return <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '100%', color: 'var(--text-muted)' }}>Loading dashboard...</div>;
    }

    return (
        <div style={{ animation: 'fadeIn 0.4s ease-out' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '32px' }}>
                <div>
                    <h1 style={{ fontSize: '2rem', marginBottom: '8px', color: 'var(--text-primary)', fontWeight: '800' }}>Welcome back!</h1>
                    <p style={{ color: 'var(--text-secondary)', fontSize: '1rem', margin: 0 }}>Here is what's happening with your parking today.</p>
                </div>
                <button className="btn-primary" style={{ width: 'auto', padding: '12px 24px', borderRadius: '30px', gap: '8px' }} onClick={() => navigate('/parking')}>
                    <i className="fa-solid fa-play"></i> Book Parking
                </button>
            </div>

            {/* QUICK STATS */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))', gap: '24px', marginBottom: '40px' }}>
                <div style={statCardStyle}>
                    <div style={{ ...iconWrapperStyle, background: 'rgba(37, 99, 235, 0.1)', color: 'var(--accent-primary)' }}>
                        <i className="fa-solid fa-ticket"></i>
                    </div>
                    <div>
                        <div style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--text-primary)' }}>{stats.activeBookings}</div>
                        <div style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', fontWeight: '600' }}>Active Reservations</div>
                    </div>
                </div>
                <div style={statCardStyle}>
                    <div style={{ ...iconWrapperStyle, background: 'rgba(5, 150, 105, 0.1)', color: 'var(--status-success)' }}>
                        <i className="fa-solid fa-map-location-dot"></i>
                    </div>
                    <div>
                        <div style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--text-primary)' }}>{stats.totalLots}</div>
                        <div style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', fontWeight: '600' }}>Available Locations</div>
                    </div>
                </div>
                <div style={statCardStyle}>
                    <div style={{ ...iconWrapperStyle, background: 'rgba(249, 115, 22, 0.1)', color: 'var(--brand-orange)' }}>
                        <i className="fa-solid fa-bolt"></i>
                    </div>
                    <div>
                        <div style={{ fontSize: '2rem', fontWeight: '800', color: 'var(--text-primary)' }}>24/7</div>
                        <div style={{ fontSize: '0.9rem', color: 'var(--text-secondary)', fontWeight: '600' }}>Smart Monitoring</div>
                    </div>
                </div>
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '32px' }}>
                {/* RECENT ACTIVITY */}
                <div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '16px' }}>
                        <h2 style={{ fontSize: '1.25rem', color: 'var(--text-primary)' }}>Recent Activity</h2>
                        <span onClick={() => navigate('/bookings')} style={{ color: 'var(--accent-primary)', fontSize: '0.9rem', fontWeight: '600', cursor: 'pointer' }}>View All →</span>
                    </div>

                    {stats.recentBookings.length === 0 ? (
                        <div style={{ background: 'var(--bg-secondary)', padding: '40px', borderRadius: 'var(--radius-md)', textAlign: 'center', border: 'var(--border-subtle)', color: 'var(--text-muted)' }}>
                            <i className="fa-solid fa-car-side fa-3x" style={{ marginBottom: '16px', opacity: 0.5 }}></i>
                            <p>No recent bookings found.</p>
                            <button className="btn-primary" style={{ width: 'auto', margin: '16px auto 0' }} onClick={() => navigate('/parking')}>Find Parking</button>
                        </div>
                    ) : (
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                            {stats.recentBookings.map(b => (
                                <div key={b._id} style={{ background: 'var(--bg-secondary)', padding: '20px', borderRadius: 'var(--radius-sm)', border: 'var(--border-subtle)', display: 'flex', justifyContent: 'space-between', alignItems: 'center', transition: 'var(--transition)' }} className="dashboard-widget">
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '16px' }}>
                                        <div style={{ width: '48px', height: '48px', background: 'var(--bg-tertiary)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)', fontSize: '1.2rem' }}>
                                            <i className="fa-solid fa-car"></i>
                                        </div>
                                        <div>
                                            <div style={{ fontWeight: '700', color: 'var(--text-primary)', marginBottom: '4px' }}>{b.vehicleNumber}</div>
                                            <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>
                                                {new Date(b.startTime).toLocaleString()} - {b.slotId?.slotNumber || "Unknown Slot"}
                                            </div>
                                        </div>
                                    </div>
                                    <div>
                                        {b.status === 'Active' ? (
                                             <span style={{ background: 'var(--status-success-bg)', color: 'var(--status-success)', padding: '6px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '700', letterSpacing: '0.5px' }}><i className="fa-solid fa-circle-check"></i> ACTIVE</span>
                                        ) : b.status === 'Completed' ? (
                                            <span style={{ background: 'var(--bg-tertiary)', color: 'var(--text-muted)', padding: '6px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '700' }}>COMPLETED</span>
                                        ) : (
                                            <span style={{ background: 'var(--status-danger-bg)', color: 'var(--status-danger)', padding: '6px 12px', borderRadius: '20px', fontSize: '0.8rem', fontWeight: '700' }}>{b.status}</span>
                                        )}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>

                {/* NEARBY LOCATIONS */}
                <div>
                     <h2 style={{ fontSize: '1.25rem', color: 'var(--text-primary)', marginBottom: '16px' }}>Quick Reserve</h2>
                     <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                        {lots.map(lot => (
                            <div key={lot._id} style={{ background: 'var(--bg-secondary)', padding: '16px', borderRadius: 'var(--radius-md)', border: 'var(--border-subtle)', cursor: 'pointer', transition: 'box-shadow 0.2s, transform 0.2s' }} onMouseOver={e => {e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = 'var(--shadow-md)';}} onMouseOut={e => {e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = 'none';}} onClick={() => navigate(`/slots/${lot._id}`)}>
                                <div style={{ fontWeight: '700', color: 'var(--text-primary)', marginBottom: '4px' }}>{lot.name}</div>
                                <div style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: '12px' }}><i className="fa-solid fa-location-dot"></i> {lot.location}</div>
                                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: '0.8rem', fontWeight: '600', color: 'var(--status-success)', background: 'var(--status-success-bg)', padding: '4px 8px', borderRadius: '4px' }}>{lot.availableSlots} Slots Free</span>
                                    <i className="fa-solid fa-arrow-right" style={{ color: 'var(--text-muted)' }}></i>
                                </div>
                            </div>
                        ))}
                        <button onClick={() => navigate('/parking')} style={{ background: 'none', border: '1px solid var(--accent-primary)', color: 'var(--accent-primary)', padding: '12px', borderRadius: 'var(--radius-md)', fontWeight: '600', cursor: 'pointer' }}>
                            View All Map Locations
                        </button>
                     </div>
                </div>
            </div>
        </div>
    );
}

// Inline Styles for Dashboard Components
const statCardStyle = {
    background: 'var(--bg-secondary)',
    padding: '24px',
    borderRadius: 'var(--radius-md)',
    boxShadow: 'var(--shadow-sm)',
    border: 'var(--border-subtle)',
    display: 'flex',
    alignItems: 'center',
    gap: '20px',
    transition: 'var(--transition)'
};

const iconWrapperStyle = {
    width: '64px',
    height: '64px',
    borderRadius: '16px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    fontSize: '1.8rem'
};
